const v17ReadA={id:"v17-read-a",kind:"passage",label:"Passage for Items 69-72",title:"Multilingual Flood Alerts",description:"A river town sent flood warnings only in formal Filipino. Delivery records showed that messages reached most phones, yet interviews found that some residents misunderstood the evacuation stage and meeting point. The town tested shorter alerts in Filipino and the two most-used local languages, using the same hazard level, action verb, landmark, and deadline in each version. Comprehension improved in a sample drill. Officials kept a single technical source for all translations and required back-translation so that simpler language would not change the warning's meaning.",alt:"Passage about flood alerts that reached phones but were misunderstood, then improved through shorter multilingual messages based on one technical source and checked by back-translation."};
const v17ReadB={id:"v17-read-b",kind:"passage",label:"Babasahin para sa Aytem 73-76",title:"Malamig na Imbakan ng Kooperatiba",description:"Nagpatakbo ang kooperatiba ng maliit na cold-storage room para sa isda ng mga kasapi. Sa unang buwan, bumaba ang nasisirang produkto ngunit tumaas nang malaki ang konsumo ng kuryente. Sinuri ng teknisyan ang temperatura kada oras at napansing madalas na naiiwang bukas ang pinto habang hinihiwa-hiwalay ang kahon. Naglagay ng staging table sa labas, nagtakda ng oras ng pagpasok, at inayos ang rubber seal. Bumaba ang paggamit ng kuryente nang hindi tumaas ang spoilage. Patuloy pa ring sinukat nang hiwalay ang temperatura at kalidad ng isda dahil hindi awtomatikong katumbas ng mababang konsumo ang ligtas na imbakan.",alt:"Teksto tungkol sa cold storage na nagpababa ng spoilage ngunit gumamit ng maraming kuryente, inayos sa pamamagitan ng staging, iskedyul, at seal, at patuloy na may hiwalay na pagsukat sa temperatura at kalidad."};
const v17ReadC={id:"v17-read-c",kind:"passage",label:"Passage for Items 77-80",title:"Open Contract Data",description:"A city began publishing contract titles, suppliers, amounts, delivery dates, and implementation status in a searchable portal. Downloads increased, but users reported that supplier names appeared in several formats and amendment amounts were mixed with original contract values. The procurement unit standardized identifiers and displayed original value, amendments, and current total in separate fields. It also published a data dictionary and update date. The changes made comparison easier, although the portal still did not establish whether a price was reasonable without information about quantity, specification, and market conditions.",alt:"Passage about an open contract portal improved through standard supplier identifiers, separate original and amendment values, a data dictionary, and update dates, while noting that price reasonableness needs context."};
